import React, { useState, useEffect } from 'react';
import { partnerService } from '../services/api';
import { Package, Plus, Search, X } from 'lucide-react';
import './PartnerProducts.css';

function PartnerProducts() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [buyerEmail, setBuyerEmail] = useState('');
  const [buyerSearch, setBuyerSearch] = useState([]);
  const [selectedBuyer, setSelectedBuyer] = useState(null);
  const [notes, setNotes] = useState('');
  const [searching, setSearching] = useState(false);

  useEffect(() => {
    loadProducts();
  }, []);

  const loadProducts = async () => {
    try {
      setLoading(true);
      const response = await partnerService.getProducts();
      setProducts(response.data);
      setError('');
    } catch (err) {
      console.error('Load products error:', err);
      setError('Failed to load products');
    } finally {
      setLoading(false);
    }
  };

  const searchBuyers = async (email) => {
    if (email.length < 3) {
      setBuyerSearch([]);
      return;
    }

    try {
      setSearching(true);
      const response = await partnerService.searchBuyers(email);
      setBuyerSearch(response.data);
    } catch (err) {
      console.error('Search error:', err);
      setBuyerSearch([]);
    } finally {
      setSearching(false);
    }
  };

  const handleCreateSale = (product) => {
    setSelectedProduct(product);
    setBuyerEmail('');
    setSelectedBuyer(null);
    setBuyerSearch([]);
    setNotes('');
    setShowSaleModal(true);
  };

  const handleBuyerSelect = async (buyer) => {
    setSelectedBuyer(buyer);
    setBuyerEmail(buyer.email);
    setBuyerSearch([]);

    // Check if buyer can purchase
    try {
      const response = await partnerService.canSellToBuyer(selectedProduct.productId, buyer.userId);
      if (!response.data.canSell) {
        setError('This buyer has already purchased this product from another partner');
      } else {
        setError('');
      }
    } catch (err) {
      console.error('Check buyer error:', err);
    }
  };

  const handleSubmitSale = async (e) => {
    e.preventDefault();

    if (!selectedBuyer) {
      setError('Please select a buyer');
      return;
    }

    try {
      const saleData = {
        productId: selectedProduct.productId,
        buyerId: selectedBuyer.userId,
        notes: notes
      };

      await partnerService.createSale(saleData);
      setShowSaleModal(false);
      alert('Sale created successfully!');
      
      // Reset form
      setSelectedProduct(null);
      setBuyerEmail('');
      setSelectedBuyer(null);
      setNotes('');
      setError('');
    } catch (err) {
      console.error('Create sale error:', err);
      setError(err.response?.data?.message || 'Failed to create sale');
    }
  };

  const formatCurrency = (amount) => {
    return `₹${amount.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
  };

  const calculateCommission = (price, percentage) => {
    return formatCurrency((price * percentage) / 100);
  };

  if (loading) {
    return <div className="loading">Loading products...</div>;
  }

  return (
    <div className="partner-products-page">
      <div className="page-header">
        <div>
          <h1>Available Products</h1>
          <p>Browse and sell products to earn commission</p>
        </div>
      </div>

      {error && !showSaleModal && <div className="error-message">{error}</div>}

      {products.length === 0 ? (
        <div className="empty-state">
          <Package size={64} color="#ccc" />
          <h3>No Products Available</h3>
          <p>There are no products available for sale at the moment</p>
        </div>
      ) : (
        <div className="products-grid">
          {products.map((product) => (
            <div key={product.productId} className="product-card">
              <div className="product-header">
                <h3>{product.productName}</h3>
                <span className="product-price">{formatCurrency(product.price)}</span>
              </div>
              
              <p className="product-description">{product.description}</p>
              
              <div className="product-details">
                <div className="detail-row">
                  <span className="detail-label">Admin:</span>
                  <span className="detail-value">{product.adminName || 'N/A'}</span>
                </div>
                <div className="detail-row">
                  <span className="detail-label">Commission:</span>
                  <span className="detail-value highlight">{product.commissionPercentage}%</span>
                </div>
                <div className="detail-row">
                  <span className="detail-label">You Earn:</span>
                  <span className="detail-value highlight">
                    {calculateCommission(product.price, product.commissionPercentage)}
                  </span>
                </div>
              </div>

              <button
                className="btn-create-sale"
                onClick={() => handleCreateSale(product)}
              >
                <Plus size={20} />
                Create Sale
              </button>
            </div>
          ))}
        </div>
      )}

      {/* Create Sale Modal */}
      {showSaleModal && selectedProduct && (
        <div className="modal-overlay" onClick={() => setShowSaleModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Create Sale - {selectedProduct.productName}</h2>
              <button className="btn-close" onClick={() => setShowSaleModal(false)}>
                <X size={24} />
              </button>
            </div>

            {error && <div className="error-message">{error}</div>}

            <div className="sale-product-info">
              <div className="info-row">
                <span>Price:</span>
                <span className="highlight">{formatCurrency(selectedProduct.price)}</span>
              </div>
              <div className="info-row">
                <span>Your Commission ({selectedProduct.commissionPercentage}%):</span>
                <span className="highlight">
                  {calculateCommission(selectedProduct.price, selectedProduct.commissionPercentage)}
                </span>
              </div>
            </div>

            <form onSubmit={handleSubmitSale} className="sale-form">
              <div className="form-group">
                <label>Buyer Email *</label>
                <div className="buyer-search-container">
                  <div className="search-input-wrapper">
                    <Search size={20} className="search-icon" />
                    <input
                      type="email"
                      value={buyerEmail}
                      onChange={(e) => {
                        setBuyerEmail(e.target.value);
                        searchBuyers(e.target.value);
                        setSelectedBuyer(null);
                      }}
                      placeholder="Search buyer by email..."
                      required
                    />
                  </div>

                  {searching && <div className="search-loading">Searching...</div>}

                  {buyerSearch.length > 0 && (
                    <div className="buyer-results">
                      {buyerSearch.map((buyer) => (
                        <div
                          key={buyer.userId}
                          className="buyer-result-item"
                          onClick={() => handleBuyerSelect(buyer)}
                        >
                          <div className="buyer-info">
                            <div className="buyer-name">{buyer.fullName}</div>
                            <div className="buyer-email">{buyer.email}</div>
                            {buyer.companyName && (
                              <div className="buyer-company">{buyer.companyName}</div>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>

                {selectedBuyer && (
                  <div className="selected-buyer">
                    <div className="selected-buyer-label">Selected Buyer:</div>
                    <div className="selected-buyer-info">
                      <div className="buyer-name">{selectedBuyer.fullName}</div>
                      <div className="buyer-email">{selectedBuyer.email}</div>
                      {selectedBuyer.companyName && (
                        <div className="buyer-company">{selectedBuyer.companyName}</div>
                      )}
                    </div>
                  </div>
                )}
              </div>

              <div className="form-group">
                <label>Notes (Optional)</label>
                <textarea
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Add any notes about this sale..."
                  rows="3"
                />
              </div>

              <div className="form-actions">
                <button
                  type="button"
                  className="btn-secondary"
                  onClick={() => setShowSaleModal(false)}
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="btn-primary"
                  disabled={!selectedBuyer}
                >
                  Create Sale
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default PartnerProducts;
